import React from "react";
import UploadImage from "./UploadImage";

function App() {
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center py-10 px-4">
      {/* Header */}
      <header className="text-center">
        <h1 className="text-4xl font-extrabold text-gray-900">Radiology & Oncology AI</h1>
        <p className="text-lg text-gray-600 mt-2">
          Upload medical images for AI-powered analysis and insights.
        </p>
      </header>

      {/* Upload Section */}
      <section className="bg-white shadow-md rounded-lg p-6 mt-6 w-full max-w-lg border border-gray-200">
        <h2 className="text-xl font-semibold text-gray-800 text-center">Upload Medical Image</h2>
        <p className="text-sm text-gray-500 text-center mb-4">Supported formats: JPG, PNG, DICOM</p>

        <div className="flex flex-col items-center">
          <UploadImage />
        </div>
      </section>

      {/* AI Report Section */}
      <section className="mt-8 w-full max-w-3xl bg-white shadow-md rounded-lg p-6 border border-gray-300">
        <h2 className="text-2xl font-bold text-gray-800 mb-4 text-center">AI Analysis Report</h2>
        <p className="text-gray-700 leading-relaxed text-center">
          The AI model has analyzed the uploaded image and detected <span className="font-semibold">relevant medical patterns</span>. 
          Please review the detailed report below for potential findings.  
          Consult a <span className="font-semibold">medical expert</span> for accurate interpretation.
        </p>
      </section>

      {/* Footer */}
      <footer className="mt-8 text-gray-500 text-sm text-center">
        © {new Date().getFullYear()} Radiology AI. All rights reserved.
      </footer>
    </div>
  );
}

export default App;
